import{_ as e,o as r,c as a,ag as o}from"./chunks/framework.6MCaaFDc.js";const m=JSON.parse('{"title":"Hardware","description":"","frontmatter":{"title":"Hardware","parent":"Systems Technologies","grand_parent":"Theory (Paper 2)","nav_order":2},"headers":[],"relativePath":"theory/systems/hardware.md","filePath":"theory/systems/hardware.md"}'),s={name:"theory/systems/hardware.md"};function n(d,t,i,l,h,c){return r(),a("div",null,[...t[0]||(t[0]=[o(`<h1 id="hardware" tabindex="-1">Hardware <a class="header-anchor" href="#hardware" aria-label="Permalink to &quot;Hardware&quot;">​</a></h1><p>Your phone processes millions of instructions every second just to display your social media feed — but which physical components make that happen? Understanding hardware means understanding <em>how</em> a computer actually works inside, not just what it does on screen.</p><p><strong>Hardware</strong> is any physical component of a computer system that you can see and touch.</p><hr><h2 id="the-computer-model" tabindex="-1">The Computer Model <a class="header-anchor" href="#the-computer-model" aria-label="Permalink to &quot;The Computer Model&quot;">​</a></h2><p>Every computer — from a smartwatch to a supercomputer — follows the same fundamental processing model:</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>INPUT → PROCESS → OUTPUT</span></span>
<span class="line"><span>            ↕</span></span>
<span class="line"><span>         STORAGE</span></span>
<span class="line"><span>            ↕</span></span>
<span class="line"><span>       COMMUNICATION</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><table tabindex="0"><thead><tr><th>Stage</th><th>What happens</th><th>Examples</th></tr></thead><tbody><tr><td><strong>Input</strong></td><td>Data enters the system from the outside world</td><td>Keyboard, mouse, microphone, scanner, webcam</td></tr><tr><td><strong>Process</strong></td><td>The CPU manipulates and transforms the data</td><td>Calculations, comparisons, logical decisions</td></tr><tr><td><strong>Output</strong></td><td>Results are presented to the user</td><td>Monitor, printer, speakers, projector</td></tr><tr><td><strong>Storage</strong></td><td>Data is saved permanently or temporarily</td><td>HDD, SSD, USB drive, SD card, cloud</td></tr><tr><td><strong>Communication</strong></td><td>Data is sent or received over a network</td><td>NIC, Wi-Fi card, modem, Bluetooth adapter</td></tr></tbody></table><div class="note custom-block github-alert"><p class="custom-block-title">Grade 10 — Foundation</p><p>You need to know the full computer model (Input → Process → Output → Storage → Communication) and be able to give a real example of a device for each stage. This is one of the most reliable questions in Paper 2 — it appears almost every year. Make sure you can also explain the role of each stage, not just name a device.</p></div><hr><h2 id="the-central-processing-unit-cpu" tabindex="-1">The Central Processing Unit (CPU) <a class="header-anchor" href="#the-central-processing-unit-cpu" aria-label="Permalink to &quot;The Central Processing Unit (CPU)&quot;">​</a></h2><p>The CPU is the <strong>brain of the computer</strong> — it carries out every instruction given to it by software. Every calculation, every comparison, every decision you see on screen was first processed here.</p><h3 id="the-fetch-decode-execute-cycle" tabindex="-1">The Fetch-Decode-Execute Cycle <a class="header-anchor" href="#the-fetch-decode-execute-cycle" aria-label="Permalink to &quot;The Fetch-Decode-Execute Cycle&quot;">​</a></h3><p>The CPU works by continuously repeating three steps:</p><ol><li><strong>Fetch</strong> — retrieve the next instruction from RAM</li><li><strong>Decode</strong> — interpret what the instruction means</li><li><strong>Execute</strong> — carry out the instruction (arithmetic, logic, or control action)</li></ol><p>This cycle happens billions of times per second in a modern CPU.</p><h3 id="cpu-performance-factors" tabindex="-1">CPU Performance Factors <a class="header-anchor" href="#cpu-performance-factors" aria-label="Permalink to &quot;CPU Performance Factors&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Factor</th><th>What it means</th><th>Effect on performance</th></tr></thead><tbody><tr><td><strong>Clock speed</strong></td><td>How many cycles the CPU completes per second (MHz/GHz)</td><td>Higher clock speed = faster processing per core</td></tr><tr><td><strong>Number of cores</strong></td><td>Independent processing units built into one CPU chip</td><td>More cores = better multitasking and parallel work</td></tr><tr><td><strong>Cache size</strong></td><td>Fast on-chip memory (L1/L2/L3) for frequently used data</td><td>Larger cache = less time waiting for data from RAM</td></tr><tr><td><strong>Generation</strong></td><td>How new the CPU architecture is (e.g. Intel 13th Gen)</td><td>Newer = more instructions processed per clock cycle</td></tr><tr><td><strong>Multi-threading</strong></td><td>One physical core handling two instruction threads at once</td><td>Better utilisation of each core&#39;s resources</td></tr></tbody></table><h3 id="clock-speed-explained" tabindex="-1">Clock Speed Explained <a class="header-anchor" href="#clock-speed-explained" aria-label="Permalink to &quot;Clock Speed Explained&quot;">​</a></h3><p>Clock speed is measured in <strong>MHz</strong> (megahertz) or <strong>GHz</strong> (gigahertz):</p><table tabindex="0"><thead><tr><th>Unit</th><th>Meaning</th></tr></thead><tbody><tr><td>1 Hz</td><td>1 cycle per second</td></tr><tr><td>1 MHz</td><td>1 000 000 cycles per second</td></tr><tr><td>1 GHz</td><td>1 000 000 000 cycles per second</td></tr></tbody></table><p>A modern 3.6 GHz CPU completes <strong>3.6 billion processing cycles every second</strong>.</p><h3 id="cores-and-multi-threading" tabindex="-1">Cores and Multi-threading <a class="header-anchor" href="#cores-and-multi-threading" aria-label="Permalink to &quot;Cores and Multi-threading&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Configuration</th><th>Description</th><th>Real-world analogy</th></tr></thead><tbody><tr><td>Single-core</td><td>One processing unit; one task at a time</td><td>One cashier serving one queue</td></tr><tr><td>Dual-core</td><td>Two processing units working simultaneously</td><td>Two cashiers, two queues</td></tr><tr><td>Quad-core</td><td>Four processing units</td><td>Four cashiers</td></tr><tr><td>Octa-core</td><td>Eight processing units</td><td>Eight cashiers</td></tr><tr><td>Multi-threading</td><td>One core processes two lightweight threads simultaneously</td><td>One cashier handles card payment and packing at once</td></tr></tbody></table><div class="tip custom-block github-alert"><p class="custom-block-title">Grade 11 — Extension</p><p>At Grade 11 you need to explain the difference between multi-core processing and multi-threading, and understand that more cores primarily benefit tasks like video editing, 3D rendering, and gaming — not simple tasks like word processing. You must also know all three cache levels (L1, L2, L3) and their roles.</p></div><div class="important custom-block github-alert"><p class="custom-block-title">Grade 12 — Mastery</p><p>Grade 12 questions ask you to <strong>motivate</strong> a CPU recommendation for a specific user type. A video editor needs many cores AND high clock speed. A basic home user doing word processing and browsing needs neither. You must name the specific performance factor and link it directly to the user&#39;s needs to earn full marks.</p></div><hr><h2 id="memory-ram-rom-and-cache" tabindex="-1">Memory: RAM, ROM, and Cache <a class="header-anchor" href="#memory-ram-rom-and-cache" aria-label="Permalink to &quot;Memory: RAM, ROM, and Cache&quot;">​</a></h2><p>The word &quot;memory&quot; is used for several very different components. They differ in speed, capacity, and whether they keep their data when power is removed.</p><hr><h3 id="ram-—-random-access-memory" tabindex="-1">RAM — Random Access Memory <a class="header-anchor" href="#ram-—-random-access-memory" aria-label="Permalink to &quot;RAM — Random Access Memory&quot;">​</a></h3><p><strong>RAM is the computer&#39;s short-term working memory.</strong> When you open any program, it is loaded from storage (HDD/SSD) into RAM so the CPU can access it quickly.</p><p>Key characteristics of RAM:</p><ul><li><strong>Volatile</strong> — all information is cleared from RAM once the computer is restarted or switched off</li><li>Holds the operating system, open applications, and any data currently being worked on</li><li>The more RAM you have, the more programs you can run simultaneously without slowdown</li><li>Measured in <strong>GB</strong> (gigabytes) — typical range: 4 GB (basic) to 64 GB+ (professional)</li></ul><h4 id="ram-types-ddr-double-data-rate" tabindex="-1">RAM Types (DDR = Double Data Rate) <a class="header-anchor" href="#ram-types-ddr-double-data-rate" aria-label="Permalink to &quot;RAM Types (DDR = Double Data Rate)&quot;">​</a></h4><table tabindex="0"><thead><tr><th>Type</th><th>Generation</th><th>Typical use</th></tr></thead><tbody><tr><td>DDR3</td><td>Older (2007–2015)</td><td>Budget and legacy systems</td></tr><tr><td>DDR4</td><td>Current mainstream (2014–present)</td><td>Most modern desktops and laptops</td></tr><tr><td>DDR5</td><td>Latest generation (2020–present)</td><td>High-end new builds</td></tr></tbody></table><p>DDR RAM transfers data <strong>twice per clock cycle</strong> (once on the rising edge, once on the falling edge) — that is what &quot;Double Data Rate&quot; means.</p><div class="note custom-block github-alert"><p class="custom-block-title">Grade 10 — Foundation</p><p>Know that RAM is volatile (temporary storage). Know that more RAM = better multitasking. Be able to explain what happens when RAM is full: the system begins using <strong>virtual memory</strong> — a section of the HDD/SSD used as overflow RAM — which is dramatically slower and causes noticeable lag.</p></div><hr><h3 id="rom-—-read-only-memory" tabindex="-1">ROM — Read-Only Memory <a class="header-anchor" href="#rom-—-read-only-memory" aria-label="Permalink to &quot;ROM — Read-Only Memory&quot;">​</a></h3><p><strong>ROM stores the computer&#39;s BIOS (Basic Input/Output System).</strong> The BIOS is the first program that runs when you switch on a computer — it checks that hardware is present and working, then loads the operating system from storage.</p><p>Key characteristics of ROM:</p><ul><li><strong>Non-volatile</strong> — data is permanently stored and is <strong>not</strong> cleared when the computer is switched off</li><li>Read-only memory can only be retrieved, but <strong>not overwritten or deleted</strong> during normal operation</li><li>Contains <strong>firmware</strong> — low-level software burned into the chip during manufacturing</li><li>The <strong>CMOS battery</strong> (a small coin-cell battery on the motherboard) keeps BIOS settings such as date, time, and boot order alive when the computer is unplugged from the wall</li></ul><div class="note custom-block github-alert"><p class="custom-block-title">Grade 10 — Foundation</p><p>The most tested ROM fact is: ROM is non-volatile and stores the BIOS. Know that if the CMOS battery dies, the computer will lose its date and time settings and may struggle to boot. ROM cannot be changed during normal use — that is the key distinction from RAM.</p></div><hr><h3 id="cache-memory" tabindex="-1">Cache Memory <a class="header-anchor" href="#cache-memory" aria-label="Permalink to &quot;Cache Memory&quot;">​</a></h3><p><strong>Cache memory is also called CPU memory.</strong> It is extremely fast and works directly with the CPU to store small amounts of information that may be needed by the CPU in the immediate future.</p><p>Think of cache as the CPU&#39;s own private notepad: instead of walking all the way to the filing cabinet (RAM) every time it needs something, the CPU keeps the most frequently used items right on its desk.</p><h4 id="cache-levels" tabindex="-1">Cache Levels <a class="header-anchor" href="#cache-levels" aria-label="Permalink to &quot;Cache Levels&quot;">​</a></h4><table tabindex="0"><thead><tr><th>Level</th><th>Location</th><th>Speed</th><th>Typical Size</th><th>Role</th></tr></thead><tbody><tr><td><strong>L1</strong></td><td>Inside each CPU core</td><td>Fastest of all</td><td>32 KB – 512 KB</td><td>Stores the instructions and data the core is using right now</td></tr><tr><td><strong>L2</strong></td><td>Inside the CPU (per core or shared)</td><td>Very fast</td><td>256 KB – 4 MB</td><td>Second-level lookup before going wider</td></tr><tr><td><strong>L3</strong></td><td>On the CPU die (shared by all cores)</td><td>Fast</td><td>4 MB – 64 MB</td><td>Shared pool available to all cores</td></tr></tbody></table><p>When the CPU needs data, it checks in order:</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>L1 cache → L2 cache → L3 cache → RAM → Storage</span></span>
<span class="line"><span>(fastest)                                (slowest)</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><ul><li><strong>Cache hit</strong> — the required data is found in cache. Fast!</li><li><strong>Cache miss</strong> — the data is not in cache; the CPU must fetch it from RAM. Slow.</li></ul><div class="tip custom-block github-alert"><p class="custom-block-title">Grade 11 — Extension</p><p>You need to know all three cache levels by name and explain the cache hit vs cache miss concept. A larger L3 cache is particularly beneficial for gaming (large game assets) and video editing (large media files). Exam questions often ask you to explain why L1 is faster than L3, and why cache is faster than RAM.</p></div><hr><h2 id="memory-comparison-table" tabindex="-1">Memory Comparison Table <a class="header-anchor" href="#memory-comparison-table" aria-label="Permalink to &quot;Memory Comparison Table&quot;">​</a></h2><p>This comparison table is tested almost every year — learn every cell.</p><table tabindex="0"><thead><tr><th>Memory</th><th>Capacity</th><th>Speed</th><th>Volatile?</th><th>Can be written?</th><th>Purpose</th></tr></thead><tbody><tr><td><strong>RAM</strong></td><td>4 GB – 64 GB (typical)</td><td>Very high</td><td>Yes — cleared on restart</td><td>Yes — constantly</td><td>Active programs and working data</td></tr><tr><td><strong>ROM</strong></td><td>A few MB</td><td>Very slow</td><td>No — permanent</td><td>No — read only</td><td>Stores BIOS firmware</td></tr><tr><td><strong>Cache</strong></td><td>KB to tens of MB</td><td>Extremely fast</td><td>Yes — cleared on restart</td><td>CPU manages it</td><td>CPU&#39;s immediate data store</td></tr><tr><td><strong>HDD</strong></td><td>500 GB – several TB</td><td>Normal/slow</td><td>No — permanent</td><td>Yes</td><td>Long-term file storage</td></tr><tr><td><strong>SSD</strong></td><td>256 GB – several TB</td><td>High</td><td>No — permanent</td><td>Yes</td><td>Long-term file storage (faster than HDD)</td></tr></tbody></table><hr><h2 id="the-motherboard" tabindex="-1">The Motherboard <a class="header-anchor" href="#the-motherboard" aria-label="Permalink to &quot;The Motherboard&quot;">​</a></h2><p>The motherboard is the <strong>main circuit board</strong> of a computer. Every other component either plugs into it or connects to it. It is the backbone that allows all parts to communicate with each other.</p><h3 id="key-motherboard-components" tabindex="-1">Key Motherboard Components <a class="header-anchor" href="#key-motherboard-components" aria-label="Permalink to &quot;Key Motherboard Components&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Component</th><th>Purpose</th></tr></thead><tbody><tr><td><strong>CPU socket</strong></td><td>Physically holds the CPU — must match the CPU&#39;s brand and socket type (e.g. Intel LGA1700)</td></tr><tr><td><strong>RAM slots (DIMM slots)</strong></td><td>Hold the RAM sticks — the number of slots determines how much RAM can be installed</td></tr><tr><td><strong>Chipset</strong></td><td>A set of chips that manages data flow between the CPU, RAM, and other components</td></tr><tr><td><strong>BIOS/UEFI chip</strong></td><td>Contains the ROM with startup firmware — the first thing that runs at boot</td></tr><tr><td><strong>CMOS battery</strong></td><td>Keeps date/time and BIOS settings alive when the PC is unplugged</td></tr><tr><td><strong>Power connector</strong></td><td>Receives power from the PSU (Power Supply Unit)</td></tr><tr><td><strong>PCI-e slots</strong></td><td>Expansion slots for GPUs, sound cards, NIC cards, and other add-in cards</td></tr><tr><td><strong>SATA connectors</strong></td><td>Connect internal HDD and SSD drives via data cables</td></tr><tr><td><strong>USB headers</strong></td><td>Internal connectors for front-panel USB ports</td></tr><tr><td><strong>Buses</strong></td><td>Printed electrical pathways carrying data between all components</td></tr></tbody></table><h3 id="expansion-cards-and-pci-e-slots" tabindex="-1">Expansion Cards and PCI-e Slots <a class="header-anchor" href="#expansion-cards-and-pci-e-slots" aria-label="Permalink to &quot;Expansion Cards and PCI-e Slots&quot;">​</a></h3><p><strong>PCI-e (Peripheral Component Interconnect Express)</strong> is the standard interface for expansion cards:</p><table tabindex="0"><thead><tr><th>Expansion card</th><th>What it adds</th></tr></thead><tbody><tr><td><strong>Graphics card (GPU)</strong></td><td>Dedicated graphics processing for gaming, video editing, and AI</td></tr><tr><td><strong>Sound card</strong></td><td>High-quality audio for music production studios</td></tr><tr><td><strong>Network Interface Card (NIC)</strong></td><td>Adds an ethernet port or Wi-Fi capability</td></tr><tr><td><strong>Capture card</strong></td><td>Records or streams gameplay footage</td></tr></tbody></table><div class="tip custom-block github-alert"><p class="custom-block-title">Grade 11 — Extension</p><p>You must know the major motherboard components and their roles for Grade 11. A common exam question is: &quot;Why can&#39;t you install any CPU into any motherboard?&quot; — the answer is that the CPU must match the motherboard&#39;s socket type. Know what PCI-e slots are used for and why the chipset matters for bus speeds.</p></div><hr><h2 id="buses" tabindex="-1">Buses <a class="header-anchor" href="#buses" aria-label="Permalink to &quot;Buses&quot;">​</a></h2><p>A <strong>bus</strong> is an electrical pathway printed onto the motherboard that carries signals between components. Think of it like a highway system — different types of data travel on different roads.</p><h3 id="the-three-types-of-bus" tabindex="-1">The Three Types of Bus <a class="header-anchor" href="#the-three-types-of-bus" aria-label="Permalink to &quot;The Three Types of Bus&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Bus type</th><th>What it carries</th><th>Direction of travel</th></tr></thead><tbody><tr><td><strong>Data bus</strong></td><td>The actual data being transferred</td><td>Bidirectional (both directions)</td></tr><tr><td><strong>Address bus</strong></td><td>The memory address specifying where data should be read from or written to</td><td>Unidirectional (CPU → memory)</td></tr><tr><td><strong>Control bus</strong></td><td>Control signals: read, write, interrupt, clock signals</td><td>Bidirectional</td></tr></tbody></table><h3 id="bus-width" tabindex="-1">Bus Width <a class="header-anchor" href="#bus-width" aria-label="Permalink to &quot;Bus Width&quot;">​</a></h3><p>The <strong>width</strong> of a bus determines how much data can travel simultaneously:</p><table tabindex="0"><thead><tr><th>Bus width</th><th>Data per cycle</th></tr></thead><tbody><tr><td>8-bit bus</td><td>8 bits at once</td></tr><tr><td>32-bit bus</td><td>32 bits at once</td></tr><tr><td>64-bit bus</td><td>64 bits at once (modern standard)</td></tr></tbody></table><p>A wider bus moves more data per cycle — like having a 6-lane highway instead of a 2-lane road.</p><div class="tip custom-block github-alert"><p class="custom-block-title">Grade 11 — Extension</p><p>The three bus types are a very common Paper 2 question. You must know: (1) what each bus carries, (2) the direction of travel for each, and (3) why the address bus is unidirectional while the data bus is bidirectional. The address bus tells the system <em>where</em> data is — it only ever travels from the CPU outward.</p></div><hr><h2 id="key-terms" tabindex="-1">Key Terms <a class="header-anchor" href="#key-terms" aria-label="Permalink to &quot;Key Terms&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Term</th><th>Definition</th></tr></thead><tbody><tr><td><strong>Hardware</strong></td><td>Any physical component of a computer that you can touch</td></tr><tr><td><strong>CPU</strong></td><td>Central Processing Unit — the component that executes all instructions</td></tr><tr><td><strong>Clock speed</strong></td><td>The number of processing cycles a CPU completes per second, measured in GHz</td></tr><tr><td><strong>Core</strong></td><td>An independent processing unit within a single CPU chip</td></tr><tr><td><strong>Multi-threading</strong></td><td>A technique where one CPU core handles two instruction threads simultaneously</td></tr><tr><td><strong>RAM</strong></td><td>Random Access Memory — volatile, high-speed temporary working memory</td></tr><tr><td><strong>Volatile</strong></td><td>Data is lost when electrical power is removed</td></tr><tr><td><strong>Non-volatile</strong></td><td>Data is retained when electrical power is removed</td></tr><tr><td><strong>ROM</strong></td><td>Read-Only Memory — non-volatile memory that stores BIOS firmware</td></tr><tr><td><strong>BIOS</strong></td><td>Basic Input/Output System — firmware that initialises hardware at startup</td></tr><tr><td><strong>Firmware</strong></td><td>Low-level software permanently stored in ROM or flash memory</td></tr><tr><td><strong>CMOS battery</strong></td><td>Coin-cell battery that keeps BIOS settings (clock, date, boot order) alive when unplugged</td></tr><tr><td><strong>Cache memory</strong></td><td>Ultra-fast CPU memory (L1/L2/L3) that stores frequently needed data close to the CPU</td></tr><tr><td><strong>Cache hit</strong></td><td>The required data is found in cache — fast result</td></tr><tr><td><strong>Cache miss</strong></td><td>The required data is not in cache — CPU must fetch from slower RAM</td></tr><tr><td><strong>Virtual memory</strong></td><td>A section of HDD/SSD used as overflow RAM when actual RAM is full — very slow</td></tr><tr><td><strong>Motherboard</strong></td><td>The main circuit board that connects and enables communication between all components</td></tr><tr><td><strong>PCI-e</strong></td><td>Peripheral Component Interconnect Express — expansion slot standard for GPUs, NICs, and other cards</td></tr><tr><td><strong>Bus</strong></td><td>An electrical pathway on the motherboard that carries data, addresses, or control signals</td></tr><tr><td><strong>Data bus</strong></td><td>Bus that carries actual data — bidirectional</td></tr><tr><td><strong>Address bus</strong></td><td>Bus that carries memory addresses — unidirectional (CPU to memory)</td></tr><tr><td><strong>Control bus</strong></td><td>Bus that carries control and command signals — bidirectional</td></tr><tr><td><strong>DDR</strong></td><td>Double Data Rate — RAM that transfers data twice per clock cycle</td></tr><tr><td><strong>Chipset</strong></td><td>Chips on the motherboard that manage data flow between the CPU and other components</td></tr><tr><td><strong>SATA</strong></td><td>Serial ATA — the connector standard used for internal HDD and SSD drives</td></tr></tbody></table><hr><h2 id="exam-focus-—-paper-2" tabindex="-1">Exam Focus — Paper 2 <a class="header-anchor" href="#exam-focus-—-paper-2" aria-label="Permalink to &quot;Exam Focus — Paper 2&quot;">​</a></h2><div class="important custom-block github-alert"><p class="custom-block-title">What Examiners Test</p><p>Hardware is examined almost every year in Paper 2. These are the question patterns you must be ready for:</p></div><p><strong>1. Define and distinguish RAM vs ROM</strong> (3–4 marks)</p><p>A strong answer contrasts: volatility, capacity, speed, purpose, and whether it can be written.</p><table tabindex="0"><thead><tr><th></th><th>RAM</th><th>ROM</th></tr></thead><tbody><tr><td>Volatile?</td><td>Yes — data lost on shutdown</td><td>No — data is permanent</td></tr><tr><td>Capacity</td><td>GBs</td><td>A few MB</td></tr><tr><td>Speed</td><td>Very fast</td><td>Very slow</td></tr><tr><td>Can be written?</td><td>Yes</td><td>No</td></tr><tr><td>Stores</td><td>Running programs and data</td><td>BIOS firmware</td></tr></tbody></table><p><strong>2. Explain why RAM is described as volatile</strong> (2 marks)</p><blockquote><p>RAM is volatile because all data stored in it is lost/erased when the computer is switched off or restarted. It requires continuous electrical power to maintain its contents.</p></blockquote><p><strong>3. Explain the role of cache memory / distinguish L1, L2, L3</strong> (3–6 marks)</p><ul><li>Cache is very fast memory that sits between the CPU and RAM</li><li>L1 is the fastest and smallest — stores what the current core is actively using</li><li>L2 is larger and slightly slower — a second-level store per core</li><li>L3 is the largest and shared by all cores — last stop before RAM</li></ul><p><strong>4. Name and describe THREE types of bus</strong> (6 marks)</p><ul><li><strong>Data bus</strong>: carries actual data; bidirectional</li><li><strong>Address bus</strong>: carries memory addresses; unidirectional (CPU → memory)</li><li><strong>Control bus</strong>: carries control signals (read/write/interrupt); bidirectional</li></ul><p><strong>5. List FOUR factors that affect CPU performance</strong> (4 marks)</p><ul><li>Clock speed (GHz), number of cores, cache size (L1/L2/L3), CPU generation</li></ul><p><strong>6. Complete or draw the computer model with examples</strong> (5 marks)</p><ul><li>Input (keyboard), Process (CPU), Output (monitor), Storage (HDD/SSD), Communication (NIC/modem)</li></ul><p><strong>Command words to watch:</strong></p><ul><li><em>Define</em> — give the exact technical meaning</li><li><em>Describe</em> — explain in detail with context</li><li><em>Distinguish / Differentiate</em> — explain the differences between two things</li><li><em>Motivate</em> — give reasons backed by evidence</li><li><em>List</em> — give items without explanation (unless the question says &quot;and explain&quot;)</li></ul>`,98)])])}const u=e(s,[["render",n]]);export{m as __pageData,u as default};
